# -*- coding: utf-8 -*-
from fpdf import FPDF
from PIL import Image
FD="/usr/share/fonts/truetype/dejavu"
NAVY=(20,35,63); INK=(33,37,43); GREY=(95,102,112); SOFT=(238,241,247); LINE=(214,219,228); WHITE=(255,255,255); ACCENT=(176,141,87)
class M(FPDF):
    def __init__(self):
        super().__init__("P","mm","A4"); self.set_auto_page_break(True,16)
        self.add_font("S","",f"{FD}/DejaVuSans.ttf"); self.add_font("S","B",f"{FD}/DejaVuSans-Bold.ttf")
        self.add_font("R","",f"{FD}/DejaVuSerif.ttf"); self.add_font("R","B",f"{FD}/DejaVuSerif-Bold.ttf")
        self.set_margins(20,20,20); self.cw=170
    def header(self):
        if self.page_no()==1: return
        self.set_y(8); self.set_font("R","B",9); self.set_text_color(*NAVY); self.cell(0,5,"STRIKER",align="L")
        self.set_font("S","",7.5); self.set_text_color(*GREY); self.set_xy(20,8); self.cell(self.cw,5,"Краткий инвестиционный меморандум",align="R")
        self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,15,190,15); self.set_y(20)
    def footer(self):
        self.set_y(-13); self.set_draw_color(*LINE); self.set_line_width(0.2); self.line(20,self.get_y(),190,self.get_y())
        self.set_y(-11); self.set_font("S","",7); self.set_text_color(*GREY)
        self.cell(self.cw-20,5,"Строго конфиденциально · STRIKER · для предварительного обсуждения",align="L"); self.cell(20,5,f"{self.page_no()}",align="R")
    def section(self,num,title):
        self.add_page(); y=self.get_y()
        self.set_fill_color(*NAVY); self.rect(20,y+0.4,6.8,6.8,"F")
        self.set_font("S","B",9.5); self.set_text_color(*WHITE); self.set_xy(20,y+1.6); self.cell(6.8,4.6,num,align="C")
        self.set_font("R","B",13.5); self.set_text_color(*NAVY); self.set_xy(29.2,y+0.4); self.cell(0,7,title)
        self.ln(10); self.set_draw_color(*NAVY); self.set_line_width(0.4); self.line(20,self.get_y(),190,self.get_y()); self.ln(3)
    def body(self,txt,size=9.5,after=2.4):
        self.set_font("S","",size); self.set_text_color(*INK); self.multi_cell(self.cw,4.8,txt,align="J"); self.ln(after)
    def bullet(self,lead,txt,size=9.5,bold=False):
        t=(("**"+lead.strip()+"** ") if (bold and lead) else ((lead.strip()+" ") if lead else ""))+txt
        self.set_font("S","",size)
        n=len(self.multi_cell(self.cw-6,4.8,t,dry_run=True,output="LINES",markdown=True))
        if self.get_y()+n*4.8+2.4>277: self.add_page()
        y=self.get_y(); self.set_font("S","B",9.5); self.set_text_color(*ACCENT); self.set_xy(20,y); self.cell(6,4.8,"—")
        self.set_text_color(*INK); self.set_font("S","",size); self.set_xy(26,y); self.multi_cell(self.cw-6,4.8,t,align="J",markdown=True); self.ln(1.8)
    def img(self,path,w=160,cap=None):
        iw,ih=Image.open(path).size; h=w*ih/iw
        if self.get_y()+h+(7 if cap else 0)>278: self.add_page()
        x=20+(self.cw-w)/2; self.image(path,x=x,y=self.get_y(),w=w); self.set_y(self.get_y()+h+1.8)
        if cap:
            self.set_font("S","",7.8); self.set_text_color(*GREY); self.multi_cell(self.cw,3.8,cap,align="C"); self.ln(1.5)
    def kvtable(self,rows,kw=54):
        self.set_draw_color(*LINE); vw=self.cw-kw
        for k,v in rows:
            self.set_font("S","",8.9); n=len(self.multi_cell(vw-4,4.4,v,dry_run=True,output="LINES")); rh=max(7.2,4.4*n+3)
            if self.get_y()+rh>276: self.add_page()
            y=self.get_y(); self.set_fill_color(*SOFT); self.rect(20,y,kw,rh,"F")
            self.set_draw_color(*LINE); self.set_line_width(0.2); self.rect(20,y,kw,rh); self.rect(20+kw,y,vw,rh)
            self.set_font("S","B",8.9); self.set_text_color(*NAVY); self.set_xy(22,y+1.9); self.multi_cell(kw-3,4.4,k)
            self.set_font("S","",8.9); self.set_text_color(*INK); self.set_xy(22+kw,y+1.9); self.multi_cell(vw-4,4.4,v); self.set_y(y+rh)
    def table(self,headers,rows,widths):
        self.set_font("S","B",8.2)
        hn=max(len(self.multi_cell(w-3,3.8,h,dry_run=True,output="LINES")) for w,h in zip(widths,headers))
        hh=max(7.2,3.8*hn+3.2); y=self.get_y(); self.set_fill_color(*NAVY); self.rect(20,y,self.cw,hh,"F")
        self.set_text_color(*WHITE); cx=20
        for w,h in zip(widths,headers):
            self.set_xy(cx+1.7,y+1.6); self.multi_cell(w-3,3.8,h); cx+=w
        self.set_y(y+hh)
        for i,row in enumerate(rows):
            self.set_font("S","",8.3); n=max(len(self.multi_cell(widths[j]-3,4.0,c,dry_run=True,output="LINES")) for j,c in enumerate(row))
            rh=max(6.4,4.0*n+2.6); yy=self.get_y()
            if i%2==1: self.set_fill_color(248,249,252); self.rect(20,yy,self.cw,rh,"F")
            self.set_draw_color(*LINE); self.set_line_width(0.2); self.rect(20,yy,self.cw,rh)
            cx=20
            for j,c in enumerate(row):
                self.set_font("S","B",8.3) if j==0 else self.set_font("S","",8.3)
                self.set_text_color(*(NAVY if j==0 else INK)); self.set_xy(cx+1.5,yy+1.4); self.multi_cell(widths[j]-3,4.0,c); cx+=widths[j]
            self.set_y(yy+rh)

