p.set_y(70); p.set_font("S","",8.2); p.set_text_color(*GREY); p.cell(0,4,"СТРОГО КОНФИДЕНЦИАЛЬНО · ДЛЯ ПРЕДВАРИТЕЛЬНОГО ОБСУЖДЕНИЯ · 2026",align="C")
